import * as fs from 'fs'
import * as path from 'path'

// Add this interface near other interfaces
interface AIFailureContext {
  test_id: string
  timestamp: string
  file: string
  suite: string[]
  test: string
  error: {
    message: string
    type: string
    location: string
  }
  steps: string[]
  last_step: string
  duration_ms: number
  retries: number
  last_api?: {
    method: string
    url: string
    status: number
    operation?: string
  }
  page_url?: string
  browser?: string
  logs?: LogEntry[]
  execution?: {
    run_id: string
    branch: string
    commit_sha: string
  }
}

// Add this helper function
function buildAIContext(
  test: TestCase,
  result: TestResult,
  logs: LogEntry[],
  execution: ExecutionPayload
): AIFailureContext {
  const testFile = path.relative(process.cwd(), test.location.file)
  const testId = `${testFile}::${test.title}`

  // Parse error type from message or stack
  const errorMessage = result.error?.message || 'Unknown error'
  const errorStack = result.error?.stack || ''
  const errorType = parseErrorType(errorMessage, errorStack)
  const errorLocation = parseErrorLocation(errorStack, testFile)

  // Extract test steps from Playwright's result.steps
  const steps = result.steps
    .filter(s => s.category === 'test.step')
    .map(s => s.title)
    .slice(-10) // Last 10 steps

  const lastStep = steps[steps.length - 1] || 'Unknown'

  // Extract last API call from logs or annotations
  const lastApi = extractLastApiCall(logs, result.attachments)

  // Extract page URL from logs
  const pageUrl = extractPageUrl(logs)

  return {
    test_id: testId,
    timestamp: new Date().toISOString(),
    file: testFile,
    suite: test.titlePath().slice(0, -1), // All but test name
    test: test.title,
    error: {
      message: errorMessage,
      type: errorType,
      location: errorLocation
    },
    steps,
    last_step: lastStep,
    duration_ms: result.duration,
    retries: result.retry,
    last_api: lastApi,
    page_url: pageUrl,
    browser: test.parent.project()?.use?.defaultBrowserType || 'chromium',
    logs: logs.slice(-20), // Last 20 logs for context
    execution: {
      run_id: execution.run_id,
      branch: execution.branch,
      commit_sha: execution.commit_sha
    }
  }
}

function parseErrorType(message: string, stack: string): string {
  // Common Playwright error types
  if (message.includes('Timeout') || message.includes('exceeded')) return 'TimeoutError'
  if (message.includes('strict mode violation')) return 'StrictModeError'
  if (message.includes('expect(')) return 'AssertionError'
  if (message.includes('navigation')) return 'NavigationError'
  if (message.includes('net::')) return 'NetworkError'
  if (stack.includes('AssertionError')) return 'AssertionError'
  return 'Error'
}

function parseErrorLocation(stack: string, testFile: string): string {
  // Find first line in stack that matches test file
  const lines = stack.split('\n')
  for (const line of lines) {
    if (line.includes(testFile)) {
      const match = line.match(/:(\d+):(\d+)/)
      if (match) {
        return `${testFile}:${match[1]}:${match[2]}`
      }
    }
  }
  return testFile
}

function extractLastApiCall(logs: LogEntry[], attachments: any[]): AIFailureContext['last_api'] | undefined {
  // Look for API logs (logged via logger.api())
  const apiLogs = logs.filter(l => l.source?.includes('api') || l.message?.includes('/graphql'))
  if (apiLogs.length > 0) {
    const lastApi = apiLogs[apiLogs.length - 1]
    return {
      method: lastApi.data?.method || 'POST',
      url: lastApi.data?.url || '/graphql',
      status: lastApi.data?.status || 200,
      operation: lastApi.data?.operation
    }
  }

  // Fallback: check annotations for last-api
  const apiAnnotation = attachments?.find(a => a.name === 'last-api')
  if (apiAnnotation?.body) {
    try {
      return JSON.parse(apiAnnotation.body.toString())
    } catch { /* ignore */ }
  }

  return undefined
}

function extractPageUrl(logs: LogEntry[]): string | undefined {
  // Look for navigation logs
  const navLogs = logs.filter(l =>
    l.source?.includes('navigation') ||
    l.message?.includes('Navigate') ||
    l.data?.url
  )
  if (navLogs.length > 0) {
    return navLogs[navLogs.length - 1].data?.url as string
  }
  return undefined
}


// Add this after line ~220 (after status check for failed/timedout)
// Inside onTestEnd method, after determining test has failed:

if (status === 'failed' || status === 'timedout') {
  // Build AI context for failed test
  const aiContext = buildAIContext(test, result, logs, this.execution)

  // Export local JSON file for Claude Code
  this.exportLocalJson(aiContext)

  // Store in result for dashboard API
  testResult.ai_context = aiContext
}


private exportLocalJson(aiContext: AIFailureContext): void {
  try {
    // Create ai-failures directory if it doesn't exist
    const outputDir = path.join(process.cwd(), 'automation', 'playwright', 'ai-failures')
    if (!fs.existsSync(outputDir)) {
      fs.mkdirSync(outputDir, { recursive: true })
    }

    // Sanitize testId for filename (replace special chars)
    const safeTestId = aiContext.test_id
      .replace(/[^a-zA-Z0-9_-]/g, '_')
      .replace(/_+/g, '_')
      .slice(0, 200) // Limit filename length

    const filename = `${safeTestId}.json`
    const filepath = path.join(outputDir, filename)

    // Write JSON file
    fs.writeFileSync(filepath, JSON.stringify(aiContext, null, 2))

    // Log for visibility (only locally)
    if (!process.env.CI) {
      console.log(`[AI-Context] Exported: ${filepath}`)
    }
  } catch (error) {
    // Never fail test execution due to JSON export
    console.error('[AI-Context] Failed to export:', error)
  }
}


